                                self.sendResponseToWeb(webView: webView, callbackId: callbackId, success: success, data: ["productId": productId, "status": success ? "purchased" : "failed"])
                            }
                        } else {
                            print("Native: In-app purchase failed - missing productId")
                            self.sendResponseToWeb(webView: webView, callbackId: callbackId, success: false, data: ["error": "missing productId"])
                        }
                    case "getDeviceInfo":
                        // Example: Return device info
