            // Execute JavaScript to call the callback function in the web view
            let js = "window.nativeCallbacks['\(callbackId)'](\(jsonString)); delete window.nativeCallbacks['\(callbackId)'];"
            webView.evaluateJavaScript(js) { result, error in
                if let error = error {
